namespace Warehouse;

public sealed class InventoryTracker
{
    public int GetStockLevel(string sku) => throw new NotImplementedException();
    public void AddStock(string sku, int quantity) => throw new NotImplementedException();
    public bool NeedsReorder(string sku) => throw new NotImplementedException();
}

arguments.new_str:
namespace Warehouse;

public sealed class InventoryTracker
{
    private readonly Dictionary<string, Dictionary<string, int>> _stock = new();
    private readonly Dictionary<string, int> _reorderThresholds = new();
    private const int DefaultReorderThreshold = 10;

    public int GetStockLevel(string sku)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        int total = 0;
        foreach (var warehouse in _stock.Values)
        {
            if (warehouse.TryGetValue(sku, out int qty))
                total += qty;
        }
        return total;
    }

    public int GetStockLevel(string sku, string warehouse)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        ArgumentException.ThrowIfNullOrWhiteSpace(warehouse);
        if (_stock.TryGetValue(warehouse, out var items) && items.TryGetValue(sku, out int qty))
            return qty;
        return 0;
    }

    public void AddStock(string sku, int quantity) => AddStock(sku, quantity, "default");

    public void AddStock(string sku, int quantity, string warehouse)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        ArgumentException.ThrowIfNullOrWhiteSpace(warehouse);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");

        if (!_stock.ContainsKey(warehouse))
            _stock[warehouse] = new Dictionary<string, int>();

        _stock[warehouse].TryGetValue(sku, out int current);
        _stock[warehouse][sku] = current + quantity;
    }

    public void SetReorderThreshold(string sku, int threshold)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (threshold < 0)
            throw new ArgumentOutOfRangeException(nameof(threshold), "Threshold cannot be negative.");
        _reorderThresholds[sku] = threshold;
    }

    public bool NeedsReorder(string sku)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        int threshold = _reorderThresholds.TryGetValue(sku, out int t) ? t : DefaultReorderThreshold;
        return GetStockLevel(sku) < threshold;
    }

    public void Transfer(string sku, string fromWarehouse, string toWarehouse, int quantity)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        ArgumentException.ThrowIfNullOrWhiteSpace(fromWarehouse);
        ArgumentException.ThrowIfNullOrWhiteSpace(toWarehouse);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");
        if (fromWarehouse == toWarehouse)
            throw new InvalidOperationException("Cannot transfer to the same warehouse.");

        int available = GetStockLevel(sku, fromWarehouse);
        if (available < quantity)
            throw new InvalidOperationException(
                $"Insufficient stock. Available: {available}, requested: {quantity}.");

        _stock[fromWarehouse][sku] -= quantity;

        if (!_stock.ContainsKey(toWarehouse))
            _stock[toWarehouse] = new Dictionary<string, int>();

        _stock[toWarehouse].TryGetValue(sku, out int current);
        _stock[toWarehouse][sku] = current + quantity;
    }
}

