using Microsoft.VisualStudio.TestTools.UnitTesting;
using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public class InventoryTrackerTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    // ── GetStockLevel ────────────────────────────────────────────

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("UNKNOWN-SKU"));
    }

    [TestMethod]
    public void GetStockLevel_AfterAdd_ReturnsCorrectQuantity()
    {
        _tracker.AddStock("SKU-A", 25);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_AccumulatesMultipleAdds()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-A", 15);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_AggregatesAcrossWarehouses()
    {
        _tracker.AddStock("SKU-A", 10, "WH-East");
        _tracker.AddStock("SKU-A", 20, "WH-West");
        Assert.AreEqual(30, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_ByWarehouse_ReturnsWarehouseOnly()
    {
        _tracker.AddStock("SKU-A", 10, "WH-East");
        _tracker.AddStock("SKU-A", 20, "WH-West");
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A", "WH-East"));
    }

    [TestMethod]
    public void GetStockLevel_ByWarehouse_UnknownWarehouse_ReturnsZero()
    {
        _tracker.AddStock("SKU-A", 10, "WH-East");
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-A", "WH-North"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_NullSku_Throws()
    {
        _tracker.GetStockLevel(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_EmptySku_Throws()
    {
        _tracker.GetStockLevel("");
    }

    // ── AddStock ─────────────────────────────────────────────────

    [TestMethod]
    public void AddStock_NewSku_SetsLevel()
    {
        _tracker.AddStock("SKU-B", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void AddStock_ToSpecificWarehouse_SetsLevel()
    {
