    // ── GetStockLevel ────────────────────────────────────────────

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("UNKNOWN-SKU"));
    }

    [TestMethod]
    public void GetStockLevel_AfterAdd_ReturnsCorrectQuantity()
    {
        _tracker.AddStock("SKU-A", 25);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_AccumulatesMultipleAdds()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-A", 15);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_AggregatesAcrossWarehouses()
    {
        _tracker.AddStock("SKU-A", 10, "WH-East");
        _tracker.AddStock("SKU-A", 20, "WH-West");
        Assert.AreEqual(30, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_ByWarehouse_ReturnsWarehouseOnly()
    {
        _tracker.AddStock("SKU-A", 10, "WH-East");
        _tracker.AddStock("SKU-A", 20, "WH-West");
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A", "WH-East"));
    }

    [TestMethod]
    public void GetStockLevel_ByWarehouse_UnknownWarehouse_ReturnsZero()
    {
        _tracker.AddStock("SKU-A", 10, "WH-East");
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-A", "WH-North"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_NullSku_Throws()
    {
        _tracker.GetStockLevel(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_EmptySku_Throws()
    {
        _tracker.GetStockLevel("");
    }

    // ── AddStock ─────────────────────────────────────────────────

    [TestMethod]
    public void AddStock_NewSku_SetsLevel()
    {
        _tracker.AddStock("SKU-B", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void AddStock_ToSpecificWarehouse_SetsLevel()
    {
        _tracker.AddStock("SKU-B", 30, "WH-East");
        Assert.AreEqual(30, _tracker.GetStockLevel("SKU-B", "WH-East"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_ZeroQuantity_Throws()
    {
        _tracker.AddStock("SKU-B", 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_NegativeQuantity_Throws()
    {
        _tracker.AddStock("SKU-B", -5);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_NullSku_Throws()
    {
        _tracker.AddStock(null!, 10);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_WhitespaceSku_Throws()
    {
        _tracker.AddStock("   ", 10);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_NullWarehouse_Throws()
    {
        _tracker.AddStock("SKU-B", 10, null!);
    }

    // ── NeedsReorder ─────────────────────────────────────────────

    [TestMethod]
    public void NeedsReorder_StockBelowDefaultThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-C", 5);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-C"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtDefaultThreshold_ReturnsFalse()
    {
        _tracker.AddStock("SKU-C", 10);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-C"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveDefaultThreshold_ReturnsFalse()
    {
        _tracker.AddStock("SKU-C", 50);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-C"));
    }

    [TestMethod]
    public void NeedsReorder_UnknownSku_ReturnsTrue()
    {
        Assert.IsTrue(_tracker.NeedsReorder("NEVER-STOCKED"));
    }

    [TestMethod]
    public void NeedsReorder_CustomThreshold_Respected()
    {
        _tracker.SetReorderThreshold("SKU-C", 100);
        _tracker.AddStock("SKU-C", 50);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-C"));
    }

