        _tracker.Transfer("SKU-E", "WH-East", "WH-West", 20);

        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-E", "WH-East"));
        Assert.AreEqual(20, _tracker.GetStockLevel("SKU-E", "WH-West"));
    }

    [TestMethod]
