    public void Transfer_InsufficientStock_Throws()
    {
        _tracker.AddStock("SKU-E", 5, "WH-East");
        _tracker.Transfer("SKU-E", "WH-East", "WH-West", 10);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void Transfer_SameWarehouse_Throws()
    {
        _tracker.AddStock("SKU-E", 20, "WH-East");
        _tracker.Transfer("SKU-E", "WH-East", "WH-East", 5);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void Transfer_ZeroQuantity_Throws()
    {
        _tracker.AddStock("SKU-E", 20, "WH-East");
        _tracker.Transfer("SKU-E", "WH-East", "WH-West", 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void Transfer_NegativeQuantity_Throws()
    {
        _tracker.AddStock("SKU-E", 20, "WH-East");
        _tracker.Transfer("SKU-E", "WH-East", "WH-West", -3);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void Transfer_NullSku_Throws()
    {
        _tracker.Transfer(null!, "WH-East", "WH-West", 5);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void Transfer_NullFromWarehouse_Throws()
    {
        _tracker.Transfer("SKU-E", null!, "WH-West", 5);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void Transfer_NullToWarehouse_Throws()
    {
        _tracker.Transfer("SKU-E", "WH-East", null!, 5);
    }

    // ── Integration / edge-case scenarios ────────────────────────

    [TestMethod]
    public void Transfer_ThenReorderCheck_ReflectsNewLevels()
    {
        _tracker.SetReorderThreshold("SKU-F", 20);
        _tracker.AddStock("SKU-F", 25, "WH-East");
        Assert.IsFalse(_tracker.NeedsReorder("SKU-F"));

        _tracker.Transfer("SKU-F", "WH-East", "WH-West", 10);
        // total is still 25, so no reorder
        Assert.IsFalse(_tracker.NeedsReorder("SKU-F"));
    }

