    {
        _tracker.AddStock("SKU-X", 100);
        _tracker.AddStock("SKU-Y", 3);

        Assert.IsFalse(_tracker.NeedsReorder("SKU-X"));
        Assert.IsTrue(_tracker.NeedsReorder("SKU-Y"));
        Assert.AreEqual(100, _tracker.GetStockLevel("SKU-X"));
        Assert.AreEqual(3, _tracker.GetStockLevel("SKU-Y"));
    }
}

